基础：序列处理

FASTA 文件解析器
#include &lt;iostream&gt;
#include &lt;fstream&gt;
#include &lt;string&gt;
#include &lt;vector&gt;

struct Sequence {
    std::string header;
    std::string sequence;
};

class FastaReader {
public:
    std::vector&lt;Sequence&gt; read(const std::string& filename) {
        std::vector&lt;Sequence&gt; sequences;
        std::ifstream file(filename);
        std::string line, current_seq, current_header;

        while (std::getline(file, line)) {
            if (line.empty()) continue;

            if (line[0] == '&gt;') {
                if (!current_header.empty()) {
                    sequences.push_back({current_header, current_seq});
                }
                current_header = line.substr(1);
                current_seq.clear();
            } else {
                current_seq += line;
            }
        }

        if (!current_header.empty()) {
            sequences.push_back({current_header, current_seq});
        }

        return sequences;
    }
};

int main() {
    FastaReader reader;
    auto seqs = reader.read("sequences.fa");
    std::cout &lt;&lt; "Loaded " &lt;&lt; seqs.size() &lt;&lt; " sequences\n";
    return 0;
}

进阶：序列比对算法

Smith-Waterman 局部比对
#include &lt;vector&gt;
#include &lt;algorithm&gt;

class SmithWaterman {
    static constexpr int MATCH = 2;
    static constexpr int MISMATCH = -1;
    static constexpr int GAP = -2;

public:
    struct Result {
        int score;
        std::string aligned_seq1;
        std::string aligned_seq2;
    };

    Result align(const std::string& seq1, const std::string& seq2) {
        int m = seq1.length(), n = seq2.length();
        std::vector&lt;std::vector&lt;int&gt;&gt; H(m + 1, 
            std::vector&lt;int&gt;(n + 1, 0));

        int max_score = 0;
        int max_i = 0, max_j = 0;

        for (int i = 1; i &lt;= m; i++) {
            for (int j = 1; j &lt;= n; j++) {
                int match = H[i-1][j-1] + 
                    (seq1[i-1] == seq2[j-1] ? MATCH : MISMATCH);
                int delete_gap = H[i-1][j] + GAP;
                int insert_gap = H[i][j-1] + GAP;

                H[i][j] = std::max({0, match, delete_gap, insert_gap});

                if (H[i][j] &gt; max_score) {
                    max_score = H[i][j];
                    max_i = i;
                    max_j = j;
                }
            }
        }

        return {max_score, "", ""};
    }
};

